begin;
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,email text not null,full_name text,platform_role public.platform_role not null default 'standard',status public.profile_status not null default 'invited',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.agencies(id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,status public.agency_status not null default 'active',timezone text not null default 'UTC',default_currency text not null default 'USD' check(default_currency ~ '^[A-Z]{3}$'),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.agency_members(id uuid primary key default gen_random_uuid(),agency_id uuid not null references public.agencies(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,role public.agency_member_role not null,status public.membership_status not null default 'invited',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(agency_id,user_id));
create table public.models(id uuid primary key default gen_random_uuid(),agency_id uuid references public.agencies(id) on delete set null,display_name text not null,slug text not null,profile_image_url text,source_system text not null,source_model_key text not null,telegram_identifier text,currency text not null default 'USD' check(currency ~ '^[A-Z]{3}$'),timezone text not null default 'UTC',status public.model_status not null default 'active',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(source_system,source_model_key),unique(agency_id,slug));
create table public.model_members(id uuid primary key default gen_random_uuid(),model_id uuid not null references public.models(id) on delete cascade,user_id uuid not null references public.profiles(id) on delete cascade,role public.model_member_role not null,status public.membership_status not null default 'active',created_at timestamptz not null default now(),unique(model_id,user_id));
create table public.model_access_assignments(id uuid primary key default gen_random_uuid(),agency_id uuid not null references public.agencies(id) on delete cascade,manager_user_id uuid not null references public.profiles(id) on delete cascade,model_id uuid not null references public.models(id) on delete cascade,created_by uuid not null references public.profiles(id),created_at timestamptz not null default now(),unique(manager_user_id,model_id));
create table public.transactions(id uuid primary key default gen_random_uuid(),model_id uuid not null references public.models(id),source_system text not null,source_transaction_id text not null,source_buyer_id text not null,telegram_user_id text,stars integer not null check(stars>=0),gross_amount_cents bigint not null, currency text not null check(currency ~ '^[A-Z]{3}$'),conversion_rate_micros integer check(conversion_rate_micros is null or conversion_rate_micros>=0),transaction_type text not null,transaction_status text not null,occurred_at timestamptz not null,synced_at timestamptz not null,created_at timestamptz not null default now(),unique(source_system,source_transaction_id),check(gross_amount_cents>=0 or transaction_type in ('refund','reversal')));
create table public.daily_model_metrics(id uuid primary key default gen_random_uuid(),model_id uuid not null references public.models(id) on delete cascade,metric_date date not null,stars_purchased bigint not null default 0 check(stars_purchased>=0),gross_revenue_cents bigint not null default 0,sales_count integer not null default 0 check(sales_count>=0),unique_buyers integer not null default 0 check(unique_buyers>=0),message_count bigint not null default 0 check(message_count>=0),total_users integer not null default 0 check(total_users>=0),active_users integer not null default 0 check(active_users>=0),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(model_id,metric_date));
create table public.sync_runs(id uuid primary key default gen_random_uuid(),sync_id uuid not null unique,source_system text not null,workflow_name text not null,agency_id uuid references public.agencies(id),model_id uuid references public.models(id),status public.sync_status not null,payload_hash text not null,records_received integer not null default 0,records_created integer not null default 0,records_updated integer not null default 0,records_ignored integer not null default 0,started_at timestamptz not null default now(),completed_at timestamptz,error_summary text,created_at timestamptz not null default now());
create table public.conversion_rates(id uuid primary key default gen_random_uuid(),source_system text not null,source_currency text not null,target_currency text not null,rate_micros integer not null check(rate_micros>0),effective_from timestamptz not null,effective_until timestamptz,source_description text not null,created_by uuid references public.profiles(id),created_at timestamptz not null default now(),check(effective_until is null or effective_until>effective_from));
create table public.audit_logs(id uuid primary key default gen_random_uuid(),actor_user_id uuid references public.profiles(id),agency_id uuid references public.agencies(id),model_id uuid references public.models(id),action text not null,target_type text not null,target_id uuid,metadata jsonb not null default '{}'::jsonb,ip_address inet,created_at timestamptz not null default now());
create index transactions_model_occurred_idx on public.transactions(model_id,occurred_at desc); create index transactions_model_buyer_idx on public.transactions(model_id,source_buyer_id); create index daily_metrics_model_date_idx on public.daily_model_metrics(model_id,metric_date); create index models_agency_status_idx on public.models(agency_id,status); create index agency_members_user_status_idx on public.agency_members(user_id,status); create index model_members_user_status_idx on public.model_members(user_id,status); create index assignments_manager_model_idx on public.model_access_assignments(manager_user_id,model_id); create index sync_model_completed_idx on public.sync_runs(model_id,completed_at desc); create index sync_agency_completed_idx on public.sync_runs(agency_id,completed_at desc);
commit;
